package com.example.yourapp

import android.content.Context
import android.content.SharedPreferences
import androidx.core.content.edit

class AuthManager(context: Context) {

    private val sharedPreferences: SharedPreferences

    private companion object {
        private const val PREFS_FILE_NAME = "auth_prefs"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
    }

    init {
        sharedPreferences = context.getSharedPreferences(PREFS_FILE_NAME, Context.MODE_PRIVATE)
    }

    /**
     * Saves the user's authentication token and user ID to SharedPreferences.
     * Call this method after a successful login or registration.
     *
     * @param authToken The authentication token received from the server.
     * @param userId The unique identifier for the user.
     */
    fun saveLoginState(authToken: String, userId: String) {
        sharedPreferences.edit {
            putString(KEY_AUTH_TOKEN, authToken)
            putString(KEY_USER_ID, userId)
        }
    }

    /**
     * Retrieves the stored authentication token.
     *
     * @return The authentication token if available, otherwise null.
     */
    fun getAuthToken(): String? {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null)
    }

    /**
     * Retrieves the stored user ID.
     *
     * @return The user ID if available, otherwise null.
     */
    fun getUserId(): String? {
        return sharedPreferences.getString(KEY_USER_ID, null)
